const resp = $input.first().json;
const pg = $('PG: Pages without description').item.json;
const url = pg.url || '';

// Check for API error first
if (resp.error || resp.type === 'error') {
  const errMsg = resp.error?.message || resp.message || 'API error';
  return [{ json: { ok: false, url, error: errMsg } }];
}

let content = '';
try {
  content = (resp.content || [])[0]?.text || '';
  content = content.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(content);
  return [{ json: {
    ok: true,
    url,
    description: (parsed.description || '').slice(0, 200),
    h1: (parsed.h1 || '').slice(0, 100),
    faq: JSON.stringify(parsed.faq || []),
    article: (parsed.article || '').slice(0, 2000)
  }}];
} catch(e) {
  return [{ json: { ok: false, url, error: e.message, raw: content.slice(0, 100) } }];
}

const items = $input.all();
return items.map(item => {
  const d = item.json;
  if (!d.ok || !d.url) {
    // Return no-op SELECT so PG doesn't crash on null
    return { json: { sql: "SELECT 1", skipped: true, url: d.url || '' } };
  }
  const esc = s => (s || '').replace(/'/g, "''");
  const sql = `UPDATE page_seo SET description='${esc(d.description)}',h1='${esc(d.h1)}',faq='${esc(d.faq)}'::jsonb,article='${esc(d.article)}',updated_at=now() WHERE url='${esc(d.url)}' AND lang='ru'`;
  return { json: { sql, url: d.url, ok: true } };
});

const all = $input.all();
const ok = all.filter(i => i.json.ok === true).length;
const skipped = all.filter(i => i.json.skipped).length;
const errors = all.filter(i => !i.json.ok && !i.json.skipped);
const date = new Date().toISOString().slice(0,10);

let msg = `✍️ WF-301 SEO Content\n\n`;
msg += `✅ Записано: ${ok} страниц\n`;
if (skipped > 0) msg += `⏭ Пропущено: ${skipped}\n`;
if (errors.length > 0) {
  msg += `❌ Ошибок: ${errors.length}\n`;
  // Show first error for debug
  const firstErr = errors[0]?.json;
  if (firstErr?.error) msg += `Первая ошибка: ${firstErr.error.slice(0,100)}\n`;
}
msg += `📅 ${date}`;

return [{ json: { msg } }];

// Pass the current item back to the loop
// regardless of what PG Write returned
const item = $('Build SQL').first().json;
return [{ json: { url: item.url, done: true } }];
